from __future__ import annotations

import asyncio
from typing import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    """Run async jobs with at most ``max_concurrent`` running concurrently.

    If this coroutine is cancelled, for example because the program receives
    Ctrl+C, active jobs are cancelled and awaited so their cleanup code can
    execute before this function returns.
    """
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be greater than zero")

    if not tasks:
        return

    queue = asyncio.Queue()
    for task in tasks:
        queue.put_nowait(task)

    worker_count = min(max_concurrent, len(tasks))
    for _ in range(worker_count):
        queue.put_nowait(None)

    async def worker() -> None:
        while True:
            factory = await queue.get()
            try:
                if factory is None:
                    return
                await factory()
            finally:
                queue.task_done()

    workers = [asyncio.create_task(worker()) for _ in range(worker_count)]

    try:
        await asyncio.gather(*workers)
    except BaseException:
        for worker_task in workers:
            if not worker_task.done():
                worker_task.cancel()

        # Wait for cancelled workers even if interrupted again, so CancelledError
        # is delivered to active jobs and their finally blocks can run.
        while not all(worker_task.done() for worker_task in workers):
            try:
                await asyncio.gather(*workers, return_exceptions=True)
            except asyncio.CancelledError:
                for worker_task in workers:
                    if not worker_task.done():
                        worker_task.cancel()

        raise
